import java.util.*;

public class StackQueueExample {
    public static void main(String[] args) {
        // 1. Stack (LIFO — Last In, First Out)
        System.out.println("=== Stack (LIFO) ===");
        Stack<String> stack = new Stack<>();

        // Push — add to top
        stack.push("First");
        stack.push("Second");
        stack.push("Third");
        System.out.println("Stack: " + stack);

        // Peek — look at top without removing
        System.out.println("Peek: " + stack.peek());

        // Pop — remove and return top
        System.out.println("Pop: " + stack.pop());
        System.out.println("After pop: " + stack);
        System.out.println("Is empty? " + stack.isEmpty());

        // 2. Queue (FIFO — First In, First Out)
        System.out.println("=== Queue (FIFO) ===");
        // Using LinkedList as Queue
        Queue<String> queue = new LinkedList<>();

        // Offer — add to end
        queue.offer("First");
        queue.offer("Second");
        queue.offer("Third");
        System.out.println("Queue: " + queue);

        // Peek — look at front without removing
        System.out.println("Peek: " + queue.peek());

        // Poll — remove and return front
        System.out.println("Poll: " + queue.poll());
        System.out.println("After poll: " + queue);
        System.out.println("Is empty? " + queue.isEmpty());

        // 3. Deque (Double-ended queue)
        System.out.println("=== Deque (Double-ended) ===");
        Deque<String> deque = new LinkedList<>();

        // Add to both ends
        deque.addFirst("First");
        deque.addLast("Second");
        deque.addFirst("Zero");
        System.out.println("Deque: " + deque);

        // Remove from both ends
        System.out.println("Remove First: " + deque.removeFirst());
        System.out.println("Remove Last: " + deque.removeLast());
        System.out.println("After removals: " + deque);

        // 4. ArrayDeque (more efficient than LinkedList for stack/queue)
        System.out.println("=== ArrayDeque ===");
        // As a stack
        Deque<String> arrayStack = new ArrayDeque<>();
        arrayStack.push("A");
        arrayStack.push("B");
        arrayStack.push("C");
        System.out.println("ArrayDeque as stack: " + arrayStack);
        System.out.println("Pop: " + arrayStack.pop());

        // As a queue
        Deque<Integer> arrayQueue = new ArrayDeque<>();
        arrayQueue.offer(10);
        arrayQueue.offer(20);
        arrayQueue.offer(30);
        System.out.println("ArrayDeque as queue: " + arrayQueue);
        System.out.println("Poll: " + arrayQueue.poll());
        System.out.println("After poll: " + arrayQueue);

        // 5. PriorityQueue (sorted order)
        System.out.println("=== PriorityQueue ===");
        PriorityQueue<Integer> pq = new PriorityQueue<>();
        pq.offer(30);
        pq.offer(10);
        pq.offer(20);
        pq.offer(5);
        System.out.println("PriorityQueue: " + pq);

        System.out.println("Poll in order:");
        while (!pq.isEmpty()) {
            System.out.print(pq.poll() + " ");
        }
        System.out.println();

        // 6. Usage examples
        System.out.println("=== Use Cases ===");
        System.out.println("Stack: Undo operations, back navigation, parsing");
        System.out.println("Queue: Task scheduling, print jobs, message processing");
        System.out.println("Deque: Sliding window, palindrome checking");
        System.out.println("PriorityQueue: Task prioritization, Dijkstra's algorithm");

        // 7. When to use
        System.out.println("=== Recommendations ===");
        System.out.println("Stack: Use ArrayDeque over Stack (faster, more efficient)");
        System.out.println("Queue: Use ArrayDeque over LinkedList for Queue");
        System.out.println("Deque: Use ArrayDeque over LinkedList when you need both ends");
        System.out.println("PriorityQueue: Use for sorted access");
    }
}

